import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def pkg_map(data):
    result = {}
    for proj in data['projects']:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (pname, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = pkg_map(baseline)
a = pkg_map(after)

changes = []
unchanged = []
for k in sorted(set(list(b.keys()) + list(a.keys()))):
    proj, fw, pkg = k
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    if bv != av:
        changes.append((proj, fw, pkg, bv, av))
    else:
        unchanged.append((proj, fw, pkg, bv))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'{c[0]:20s} {c[1]:10s} {c[2]:50s} {c[3]:10s} -> {c[4]}')
else:
    print('None')

print()
print(f'=== UNCHANGED ({len(unchanged)} entries) ===')
for u in unchanged:
    print(f'{u[0]:20s} {u[1]:10s} {u[2]:50s} {u[3]}')
"

